customCss:
/* 全局样式 */
.resume-renderer {
  font-family: var(--typography-fontFamily-body);
  color: var(--colors-text-primary);
  line-height: var(--typography-lineHeight-normal);
  background-color: var(--colors-background);
}

/* 基本信息样式 */
.section-basic,
.section-basic-wrapper {
  text-align: center;
}

.section-basic .section-content,
.section-basic-wrapper .section-content {
  display: flex;
  flex-direction: column;
  align-items: center;
}

.section-basic img,
.section-basic-wrapper img {
  width: 100px;
  height: 100px;
  border-radius: 50%;
  object-fit: cover;
  border: 3px solid var(--colors-primary);
  margin-bottom: 15px;
}

/* 时间轴样式 */
.column-left::before {
  content: '';
  position: absolute;
  top: 0;
  bottom: 0;
  left: 40px;
  width: 2px;
  background-color: var(--colors-primary);
  z-index: 1;
}

.column-right::before {
  content: '';
  position: absolute;
  top: 0;
  bottom: 0;
  left: 30px;
  width: 2px;
  background-color: var(--colors-primary);
  z-index: 1;
}

/* 时间轴节点 */
.section-education .section-title::before,
.section-skills .section-title::before,
.section-awards .section-title::before,
.section-summary .section-title::before,
.section-experience .section-title::before,
.section-projects .section-title::before,
.section-education-wrapper .section-title::before,
.section-skills-wrapper .section-title::before,
.section-awards-wrapper .section-title::before,
.section-summary-wrapper .section-title::before,
.section-experience-wrapper .section-title::before,
.section-projects-wrapper .section-title::before {
  content: '';
  position: absolute;
  left: -30px;
  top: 50%;
  transform: translateY(-50%);
  width: 40px;
  height: 40px;
  border-radius: 50%;
  background-color: var(--colors-primary);
  z-index: 2;
  display: flex;
  align-items: center;
  justify-content: center;
  color: white;
  font-weight: var(--typography-fontWeight-bold);
}

/* 经验项样式 */
.section-experience-item,
.section-projects-item {
  margin-bottom: 20px;
  padding-bottom: 20px;
  border-bottom: 1px solid var(--colors-border);
}

.section-experience-item:last-child,
.section-projects-item:last-child {
  border-bottom: none;
}

/* 时间和公司样式 */
.experience-header,
.project-header {
  display: flex;
  justify-content: space-between;
  margin-bottom: 10px;
  font-weight: var(--typography-fontWeight-bold);
}

.experience-time,
.project-time {
  color: var(--colors-primary);
}

.experience-company,
.project-company {
  color: var(--colors-text-primary);
}

/* 职位样式 */
.experience-position,
.project-role {
  margin-bottom: 10px;
  color: var(--colors-text-secondary);
  font-style: italic;
}

/* 描述列表样式 */
.experience-description,
.project-description {
  margin-left: 20px;
  list-style-type: disc;
}

.experience-description li,
.project-description li {
  margin-bottom: 5px;
}

/* 技能样式 */
.section-skills-content,
.section-skills-wrapper .section-content {
  display: flex;
  flex-direction: column;
}

.skill-group {
  margin-bottom: 15px;
}

.skill-name {
  font-weight: var(--typography-fontWeight-bold);
  margin-bottom: 5px;
}

.skill-level {
  height: 8px;
  background-color: var(--colors-border);
  border-radius: 4px;
  overflow: hidden;
}

.skill-level-bar {
  height: 100%;
  background-color: var(--colors-primary);
}

/* 教育背景样式 */
.education-item {
  margin-bottom: 20px;
}

.education-school {
  font-weight: var(--typography-fontWeight-bold);
  color: var(--colors-text-primary);
}

.education-degree {
  color: var(--colors-text-secondary);
  font-style: italic;
  margin-bottom: 5px;
}

.education-time {
  color: var(--colors-primary);
  margin-bottom: 5px;
}

/* 联系信息样式 */
.contact-info {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: 10px;
  margin-top: 15px;
}

.contact-item {
  display: flex;
  align-items: center;
}

.contact-icon {
  width: 20px;
  height: 20px;
  margin-right: 10px;
  color: var(--colors-primary);
}

/* 图标样式 */
.icon {
  display: inline-block;
  width: 24px;
  height: 24px;
  background-color: var(--colors-primary);
  color: white;
  border-radius: 50%;
  text-align: center;
  line-height: 24px;
  margin-right: 8px;
}

/* 确保基本模块标题不显示时间轴节点 */
.section-basic .section-title::before,
.section-basic-wrapper .section-title::before {
  display: none !important;
}
